    18→// PluginSettings maps plugin id to map of key/value settings.
    19→type PluginSettings map[string]map[string]string
    20→
    21→func extractPluginSettings(sections []*ini.Section) PluginSettings {
    22→	psMap := PluginSettings{}
    23→	for _, section := range sections {
    24→		sectionName := section.Name()
    25→		if !strings.HasPrefix(sectionName, "plugin.") {
    26→			continue
    27→		}
    28→
    29→		pluginID := strings.Replace(sectionName, "plugin.", "", 1)
