    31→	}
    32→
    33→	return psMap
    34→}
    35→
    36→var (
    37→	defaultPreinstallPlugins = map[string]InstallPlugin{
    38→		// Default preinstalled plugins
    39→		"grafana-lokiexplore-app":      {ID: "grafana-lokiexplore-app"},
