    17→	"github.com/grafana/grafana/pkg/util"
    18→)
    19→
    20→var walk = util.Walk
    21→
    22→var (
    23→	ErrInvalidPluginJSONFilePath = errors.New("invalid plugin.json filepath was provided")
    24→)
    25→
    26→type LocalSource struct {
    27→	paths      []string
    28→	class      plugins.Class
    29→	strictMode bool // If true, tracks files via a StaticFS
    30→	log        log.Logger
    31→}
    32→
    33→// NewLocalSource represents a plugin with a fixed set of files.
    34→func NewLocalSource(class plugins.Class, paths []string) *LocalSource {
    35→	return &LocalSource{
    36→		paths:      paths,
    37→		class:      class,
    38→		strictMode: true,
    39→		log:        log.New("local.source"),
    40→	}
    41→}
    42→
    43→// NewUnsafeLocalSource represents a plugin that has an unbounded set of files. This useful when running in
    44→// dev mode whilst developing a plugin.
    45→func NewUnsafeLocalSource(class plugins.Class, paths []string) *LocalSource {
    46→	return &LocalSource{
    47→		paths:      paths,
    48→		class:      class,
    49→		strictMode: false,
    50→		log:        log.New("local.source"),
    51→	}
    52→}
    53→
    54→func (s *LocalSource) PluginClass(_ context.Context) plugins.Class {
    55→	return s.class
    56→}
    57→
    58→// Paths returns the file system paths that this source will search for plugins.
    59→// This method is primarily intended for testing purposes.
    60→func (s *LocalSource) Paths() []string {
    61→	return s.paths
    62→}
    63→
    64→func (s *LocalSource) DefaultSignature(_ context.Context, _ string) (plugins.Signature, bool) {
    65→	switch s.class {
    66→	case plugins.ClassCore:
    67→		return plugins.Signature{
    68→			Status: plugins.SignatureStatusInternal,
    69→		}, true
    70→	default:
    71→		return plugins.Signature{}, false
    72→	}
    73→}
    74→
    75→func (s *LocalSource) Discover(_ context.Context) ([]*plugins.FoundBundle, error) {
    76→	if len(s.paths) == 0 {
    77→		return []*plugins.FoundBundle{}, nil
    78→	}
    79→
    80→	pluginJSONPaths := make([]string, 0, len(s.paths))
    81→	for _, path := range s.paths {
    82→		exists, err := fs.Exists(path)
    83→		if err != nil {
    84→			s.log.Warn("Skipping finding plugins as an error occurred", "path", path, "error", err)
    85→			continue
    86→		}
    87→		if !exists {
    88→			s.log.Warn("Skipping finding plugins as directory does not exist", "path", path)
    89→			continue
    90→		}
    91→
    92→		paths, err := s.getAbsPluginJSONPaths(path)
    93→		if err != nil {
    94→			return nil, err
    95→		}
    96→		pluginJSONPaths = append(pluginJSONPaths, paths...)
    97→	}
    98→
    99→	// load plugin.json files and map directory to JSON data
   100→	foundPlugins := make(map[string]plugins.JSONData)
   101→	for _, pluginJSONPath := range pluginJSONPaths {
   102→		plugin, err := s.readPluginJSON(pluginJSONPath)
   103→		if err != nil {
   104→			s.log.Warn("Skipping plugin loading as its plugin.json could not be read", "path", pluginJSONPath, "error", err)
   105→			continue
   106→		}
   107→
   108→		pluginJSONAbsPath, err := filepath.Abs(pluginJSONPath)
   109→		if err != nil {
   110→			s.log.Warn("Skipping plugin loading as absolute plugin.json path could not be calculated", "pluginId", plugin.ID, "error", err)
   111→			continue
   112→		}
   113→
   114→		foundPlugins[filepath.Dir(pluginJSONAbsPath)] = plugin
   115→	}
   116→
   117→	res := make(map[string]*plugins.FoundBundle)
   118→	for pluginDir, data := range foundPlugins {
   119→		var pluginFs plugins.FS
   120→		pluginFs = plugins.NewLocalFS(pluginDir)
   121→		if s.strictMode {
   122→			// Tighten up security by allowing access only to the files present up to this point.
   123→			// Any new file "sneaked in" won't be allowed and will act as if the file does not exist.
   124→			var err error
   125→			pluginFs, err = plugins.NewStaticFS(pluginFs)
   126→			if err != nil {
   127→				return nil, err
   128→			}
   129→		}
   130→		res[pluginDir] = &plugins.FoundBundle{
   131→			Primary: plugins.FoundPlugin{
   132→				JSONData: data,
   133→				FS:       pluginFs,
   134→			},
   135→		}
   136→	}
   137→
   138→	// Track child plugins and add them to their parent.
   139→	childPlugins := make(map[string]struct{})
   140→	for dir, p := range res {
   141→		// Check if this plugin is the parent of another plugin.
   142→		for dir2, p2 := range res {
   143→			if dir == dir2 {
   144→				continue
   145→			}
   146→
   147→			relPath, err := filepath.Rel(dir, dir2)
   148→			if err != nil {
   149→				s.log.Error("Cannot calculate relative path. Skipping", "pluginId", p2.Primary.JSONData.ID, "err", err)
   150→				continue
   151→			}
   152→			if !strings.Contains(relPath, "..") {
   153→				child := p2.Primary
   154→				s.log.Debug("Adding child", "parent", p.Primary.JSONData.ID, "child", child.JSONData.ID, "relPath", relPath)
   155→				p.Children = append(p.Children, &child)
   156→				childPlugins[dir2] = struct{}{}
   157→			}
   158→		}
   159→	}
   160→
   161→	// Remove child plugins from the result (they are already tracked via their parent).
   162→	result := make([]*plugins.FoundBundle, 0, len(res))
   163→	for k := range res {
   164→		if _, ok := childPlugins[k]; !ok {
   165→			result = append(result, res[k])
   166→		}
   167→	}
   168→
   169→	return result, nil
   170→}
