   172→func (s *LocalSource) readPluginJSON(pluginJSONPath string) (plugins.JSONData, error) {
   173→	reader, err := s.readFile(pluginJSONPath)
   174→	defer func() {
   175→		if reader == nil {
   176→			return
   177→		}
   178→		if err = reader.Close(); err != nil {
   179→			s.log.Warn("Failed to close plugin JSON file", "path", pluginJSONPath, "error", err)
   180→		}
   181→	}()
   182→	if err != nil {
   183→		s.log.Warn("Skipping plugin loading as its plugin.json could not be read", "path", pluginJSONPath, "error", err)
   184→		return plugins.JSONData{}, err
   185→	}
   186→	plugin, err := plugins.ReadPluginJSON(reader)
   187→	if err != nil {
   188→		s.log.Warn("Skipping plugin loading as its plugin.json could not be read", "path", pluginJSONPath, "error", err)
   189→		return plugins.JSONData{}, err
   190→	}
   191→
   192→	return plugin, nil
   193→}
   194→
   195→func (s *LocalSource) getAbsPluginJSONPaths(path string) ([]string, error) {
   196→	var pluginJSONPaths []string
   197→
   198→	var err error
   199→	path, err = filepath.Abs(path)
   200→	if err != nil {
   201→		return []string{}, err
   202→	}
   203→
   204→	if err = walk(path, true, true,
   205→		func(currentPath string, fi os.FileInfo, err error) error {
   206→			if err != nil {
   207→				if errors.Is(err, os.ErrNotExist) {
   208→					s.log.Error("Couldn't scan directory since it doesn't exist", "pluginDir", path, "error", err)
   209→					return nil
   210→				}
   211→				if errors.Is(err, os.ErrPermission) {
   212→					s.log.Error("Couldn't scan directory due to lack of permissions", "pluginDir", path, "error", err)
   213→					return nil
   214→				}
   215→
   216→				return fmt.Errorf("filepath.Walk reported an error for %q: %w", currentPath, err)
   217→			}
   218→
   219→			if fi.Name() == "node_modules" {
   220→				return util.ErrWalkSkipDir
   221→			}
   222→
   223→			if fi.IsDir() {
   224→				return nil
   225→			}
   226→
   227→			if fi.Name() != "plugin.json" {
   228→				return nil
   229→			}
   230→
   231→			pluginJSONPaths = append(pluginJSONPaths, currentPath)
   232→			return nil
   233→		}); err != nil {
   234→		return []string{}, err
   235→	}
   236→
   237→	return pluginJSONPaths, nil
   238→}
   239→
   240→func (s *LocalSource) readFile(pluginJSONPath string) (io.ReadCloser, error) {
   241→	s.log.Debug("Loading plugin", "path", pluginJSONPath)
   242→
